let moduleCounter = 1
const allLanguageCourses: Course[] = []

for (const lang of LANGS) {
  allLanguageCourses.push(buildBasicCourse(lang, moduleCounter++))
  allLanguageCourses.push(buildMastersCourse(lang, moduleCounter++))
  allLanguageCourses.push(buildPhDCourse(lang, moduleCounter++))
  allLanguageCourses.push(buildNextGenCourse(lang, moduleCounter++))
}

export const languageCoursesFull: Course[] = allLanguageCourses
